// Payload esperado do ESP32:
// { "temperature": 23.5, "unit": "C", "device_id": "esp32_01" }
const p = msg.payload;

if (typeof p !== 'object' || p === null) {
    node.warn('Payload inválido: ' + JSON.stringify(p));
    return null;
}

const temp = parseFloat(p.temperature);
if (isNaN(temp) || temp < -55 || temp > 125) {
    node.warn('Temperatura fora do range DS18B20: ' + temp);
    return null;
}

msg.payload = {
    timestamp: new Date().toISOString(),
    device_id: p.device_id || 'esp32_01',
    temperature_c: temp,
    unit: p.unit || 'C',
    topic: msg.topic
};

return msg;

// Fila em memória persistida no contexto do flow
const MAX = parseInt(env.get('QUEUE_MAX_SIZE')) || 500;
const queue = flow.get('sheets_queue') || [];

queue.push({ data: msg.payload, attempts: 0, enqueued_at: Date.now() });
if (queue.length > MAX) queue.shift(); // descarta mais antigo se cheio

flow.set('sheets_queue', queue);
node.status({ fill: 'blue', shape: 'dot', text: 'Na fila: ' + queue.length });

// Dispara processamento imediatamente se não há retry ativo
const retryActive = flow.get('retry_active') || false;
if (!retryActive) return msg;
return null;

// Pega próximo item da fila
const queue = flow.get('sheets_queue') || [];
if (queue.length === 0) {
    flow.set('retry_active', false);
    node.status({ fill: 'green', shape: 'dot', text: 'Fila vazia' });
    return null;
}

const item = queue[0];
msg.payload = item.data;
msg.sheetId = env.get('GOOGLE_SHEET_ID');
msg.sheetTab = env.get('SHEET_SENSOR_READINGS');
msg._queue_item = item;

node.status({ fill: 'yellow', shape: 'ring', text: 'Enviando...' });
return msg;

// Integração via node-red-contrib-google-sheets
// Este nó requer instalação: npm install node-red-contrib-google-sheets
// Configurar credenciais em: /data/credentials/google-service-account.json

// O nó 'google-sheets' envia para a aba configurada.
// Em caso de sucesso, a saída 1 é acionada.
// Em caso de erro, a saída 2 é acionada com msg.error.

// MOCK para teste sem credenciais (remova em produção):
if (!env.get('GOOGLE_SHEET_ID') || env.get('GOOGLE_SHEET_ID') === 'cole_aqui_o_id_da_planilha') {
    node.warn('GOOGLE_SHEET_ID não configurado — simulando sucesso');
    msg._mock = true;
    return [msg, null];
}
return [msg, null];

const queue = flow.get('sheets_queue') || [];
queue.shift(); // remove o item que acabou de ser escrito
flow.set('sheets_queue', queue);
flow.set('retry_active', false);

node.status({ fill: 'green', shape: 'dot', text: 'OK — restam: ' + queue.length });

// Se ainda há itens, processa o próximo
if (queue.length > 0) {
    flow.set('retry_active', true);
    return msg;
}
return null;

const error = msg.error || {};
const statusCode = error.statusCode || error.status || 0;
const queue = flow.get('sheets_queue') || [];

if (queue.length === 0) return null;

queue[0].attempts = (queue[0].attempts || 0) + 1;
const maxAttempts = parseInt(env.get('RETRY_MAX_ATTEMPTS')) || 5;
const retryDelay = (parseInt(env.get('RETRY_DELAY_SECONDS')) || 60) * 1000;

node.warn('Erro Sheets [' + statusCode + '] tentativa ' + queue[0].attempts);

if (statusCode === 429) {
    // Rate Limit — aguarda antes de tentar
    node.status({ fill: 'yellow', shape: 'ring', text: '429 — aguardando ' + (retryDelay/1000) + 's' });
    flow.set('sheets_queue', queue);
    flow.set('retry_active', true);
    return [null, null, { payload: retryDelay }]; // saída 3 → delay
}

if (statusCode === 401) {
    // Auth Error — loga e tenta refresh
    node.status({ fill: 'red', shape: 'dot', text: '401 — Auth Error' });
    msg.errorType = 'auth';
    flow.set('sheets_queue', queue);
    flow.set('retry_active', true);
    return [null, msg, { payload: 5000 }];
}

if (queue[0].attempts >= maxAttempts) {
    // Esgotou tentativas → buffer CSV local
    node.status({ fill: 'red', shape: 'ring', text: 'Fallback CSV' });
    const item = queue.shift();
    flow.set('sheets_queue', queue);
    msg.payload = item.data;
    return [null, null, null, msg]; // saída 4 → CSV
}

// Timeout / offline — aguarda e tenta novamente
node.status({ fill: 'orange', shape: 'ring', text: 'Timeout — retry em 5min' });
flow.set('sheets_queue', queue);
flow.set('retry_active', true);
return [null, null, { payload: 300000 }];

// Salva no arquivo CSV de fallback
const d = msg.payload;
const line = [d.timestamp, d.device_id, d.temperature_c, d.unit].join(',') + '\n';
msg.filename = env.get('CSV_BUFFER_PATH') || '/data/buffer.csv';
msg.payload = line;
msg.appendNewline = false;
return msg;

msg.logEntry = {
    timestamp: new Date().toISOString(),
    event: 'sheets_error',
    error_type: msg.errorType || 'unknown',
    device_id: (msg.payload || {}).device_id || 'unknown'
};
node.warn(JSON.stringify(msg.logEntry));
return msg;
